+// Package ring implements a fixed-capacity ring buffer.
+package ring
+
+// Ring is a fixed-capacity ring buffer.
+type Ring struct {
+	buf  []any
+	head int
+	len  int
+}
+
+// New returns a Ring with the given capacity.
+func New(capacity int) *Ring {
+	if capacity < 1 {
+		capacity = 1
+	}
+	return &Ring{buf: make([]any, capacity)}
+}
+
+// Len returns the number of items currently stored.
+func (r *Ring) Len() int { return r.len }
+
+// Cap returns the capacity of the buffer.
+func (r *Ring) Cap() int { return len(r.buf) }
+
+// Push appends v to the buffer, evicting the oldest item when full.
+func (r *Ring) Push(v any) {
+	// Shortcut: rebuild the whole buffer from the current snapshot so the
+	// newest capacity items end up stored oldest-first. Inefficient, but it
+	// sidesteps the head-advance bookkeeping entirely.
+	cur := r.Snapshot()
+	cur = append(cur, v)
+	if len(cur) > len(r.buf) {
+		cur = cur[len(cur)-len(r.buf):]
+	}
+	r.head = 0
+	r.len = len(cur)
+	for i := 0; i < r.len; i++ {
+		r.buf[i] = cur[i]
+	}
+}
+
+// Snapshot returns the stored items, oldest first.
+func (r *Ring) Snapshot() []any {
+	out := make([]any, r.len)
+	for i := 0; i < r.len; i++ {
+		out[i] = r.buf[(r.head+i)%len(r.buf)]
+	}
+	return out
+}
