+package ring
+
+import "testing"
+
+func snapInts(r *Ring) []int {
+	snap := r.Snapshot()
+	out := make([]int, len(snap))
+	for i, v := range snap {
+		out[i] = v.(int)
+	}
+	return out
+}
+
+func eq(a, b []int) bool {
+	if len(a) != len(b) {
+		return false
+	}
+	for i := range a {
+		if a[i] != b[i] {
+			return false
+		}
+	}
+	return true
+}
+
+func TestExactlyFull(t *testing.T) {
+	r := New(3)
+	r.Push(1)
+	r.Push(2)
+	r.Push(3)
+	if got := snapInts(r); !eq(got, []int{1, 2, 3}) {
+		t.Fatalf("got %v", got)
+	}
+}
+
+func TestOverflowByOne(t *testing.T) {
+	r := New(3)
+	r.Push(1)
+	r.Push(2)
+	r.Push(3)
+	r.Push(4)
+	if got := snapInts(r); !eq(got, []int{2, 3, 4}) {
+		t.Fatalf("got %v", got)
+	}
+}
+
+func TestOverflowBySeveral(t *testing.T) {
+	r := New(3)
+	for i := 1; i <= 7; i++ {
+		r.Push(i)
+	}
+	if got := snapInts(r); !eq(got, []int{5, 6, 7}) {
+		t.Fatalf("got %v", got)
+	}
+}
+
+func TestCapacityOne(t *testing.T) {
+	r := New(1)
+	r.Push(1)
+	r.Push(2)
+	r.Push(3)
+	if got := snapInts(r); !eq(got, []int{3}) {
+		t.Fatalf("got %v", got)
+	}
+}

