+// Package ring implements a fixed-capacity ring buffer.
+package ring
+
+// Ring is a fixed-capacity ring buffer holding the most recently
+// pushed items.
+type Ring struct {
+	buf  []any
+	head int
+	size int
+}
+
+// New returns a ring buffer with the given capacity.
+func New(capacity int) *Ring {
+	return &Ring{buf: make([]any, capacity)}
+}
+
+// Len reports the number of items currently stored.
+func (r *Ring) Len() int { return r.size }
+
+// Cap reports the capacity.
+func (r *Ring) Cap() int { return len(r.buf) }
+
+// Push appends v, evicting the oldest item when full.
+func (r *Ring) Push(v any) {
+	if r.size < len(r.buf) {
+		r.buf[(r.head+r.size)%len(r.buf)] = v
+		r.size++
+		return
+	}
+	// Full: overwrite the oldest slot and advance the head so the
+	// next snapshot starts at the new oldest item.
+	r.buf[r.head] = v
+	r.head++
+	if r.head >= len(r.buf) {
+		r.head -= len(r.buf)
+	}
+}
+
+// Snapshot returns stored items oldest-first.
+func (r *Ring) Snapshot() []any {
+	out := make([]any, r.size)
+	for i := 0; i < r.size; i++ {
+		out[i] = r.buf[(r.head+i)%len(r.buf)]
+	}
+	return out
+}
